cards.label:
[[[
  var d = new Date().toLocaleDateString('en-GB',{weekday:'short',day:'numeric',month:'short'});
  var m = states['input_select.home_mode'] ? states['input_select.home_mode'].state : 'Home';
  return d + ' · ' + m + ' mode';
]]]

